@if is-smallest-breakpoint($name, $breakpoints) {
  .#{$prefix}--#{$name}\:col-span-auto {
    grid-column: auto;
  }

  .#{$prefix}--#{$name}\:col-span-100 {
    grid-column: 1 / -1;
  }

  $columns: get-column-count($breakpoints, $name);

  .#{$prefix}--#{$name}\:col-span-75 {
    $span: $columns * 0.75;
    --cds-grid-columns: #{$span};

    grid-column: span list.slash($span, span) #{$span};
  }

  .#{$prefix}--#{$name}\:col-span-50 {
    $span: $columns * 0.5;
    --cds-grid-columns: #{$span};

    grid-column: span list.slash($span, span) #{$span};
  }

  .#{$prefix}--#{$name}\:col-span-25 {
    $span: $columns * 0.25;
    --cds-grid-columns: #{$span};

    grid-column: span list.slash($span, span) #{$span};
  }
}

@include breakpoint($name) {
  .#{$prefix}--#{$name}\:col-span-auto {
    grid-column: auto;
  }

  .#{$prefix}--#{$name}\:col-span-100 {
    grid-column: 1 / -1;
  }

  $columns: get-column-count($breakpoints, $name);

  .#{$prefix}--#{$name}\:col-span-75 {
    $span: $columns * 0.75;
    --cds-grid-columns: #{$span};

    grid-column: span list.slash($span, span) #{$span};
  }

  .#{$prefix}--#{$name}\:col-span-50 {
    $span: $columns * 0.5;
    --cds-grid-columns: #{$span};

    grid-column: span list.slash($span, span) #{$span};
  }

  .#{$prefix}--#{$name}\:col-span-25 {
    $span: $columns * 0.25;
    --cds-grid-columns: #{$span};

    grid-column: span list.slash($span, span) #{$span};
  }
}

@mixin pseudo-underline() {
  &:not(.#{$prefix}--pagination-nav__page--direction) {
    &::after {
      position: absolute;
      display: block;
      background-color: $border-interactive;
      block-size: $spacing-02;
      content: '';
      inline-size: 0;
      inset-block-end: 0;
      inset-inline-start: 50%;
      opacity: 0;
      transition: width $duration-fast-02 motion(standard, productive);

      @media screen and (prefers-reduced-motion: reduce) {
        transition: none;
      }
    }
  }

  .#{$prefix}--pagination-nav__page--active + &::after,
  &.#{$prefix}--pagination-nav__page--active::after {
    inline-size: $spacing-05;
    inset-inline-start: calc(50% - #{$spacing-05 * 0.5});
    opacity: 1;
  }
}
